// Transform Prometheus data to ECharts wordcloud format
const words = [];

// Process data from Prometheus query
if (data.series && data.series.length > 0) {
  data.series.forEach(series => {
    const wordLabel = series.fields.find(f => f.labels && f.labels.word);
    const valueField = series.fields.find(f => f.name === 'Value' || f.type === 'number');

    if (wordLabel && valueField && valueField.values && valueField.values.length > 0) {
      const word = wordLabel.labels.word;
      const value = valueField.values[valueField.values.length - 1];
      if (word && value > 0) {
        words.push({ name: word, value: value });
      }
    }
  });
}

// Sort by value and take top 100
words.sort((a, b) => b.value - a.value);
const topWords = words.slice(0, 100);

// ECharts wordcloud configuration
return {
  tooltip: {
    show: true,
    formatter: function(params) {
      return params.name + ': ' + params.value + ' occurrences';
    }
  },
  series: [{
    type: 'wordCloud',
    shape: 'circle',
    keepAspect: false,
    left: 'center',
    top: 'center',
    width: '90%',
    height: '90%',
    right: null,
    bottom: null,
    sizeRange: [14, 80],
    rotationRange: [-45, 45],
    rotationStep: 15,
    gridSize: 8,
    drawOutOfBound: false,
    shrinkToFit: true,
    layoutAnimation: true,
    textStyle: {
      fontFamily: 'sans-serif',
      fontWeight: 'bold',
      color: function() {
        // Random color from a pleasing palette
        const colors = [
          '#5470c6', '#91cc75', '#fac858', '#ee6666', '#73c0de',
          '#3ba272', '#fc8452', '#9a60b4', '#ea7ccc', '#48b8d0'
        ];
        return colors[Math.floor(Math.random() * colors.length)];
      }
    },
    emphasis: {
      focus: 'self',
      textStyle: {
        textShadowBlur: 10,
        textShadowColor: '#333'
      }
    },
    data: topWords
  }]
};
